#include <bits/stdc++.h>
using namespace std;
int n,m,deep[30004],f[30004][18];
vector<int> g[30004];
void set_thing(){
    queue<int> b;
    b.push(1);
    deep[1]=1;
    while(b.size()){
        int u=b.front();
        b.pop();
        int len=g[u].size();
        for(int i=0;i<len;i++)
            if(!deep[g[u][i]]){
                int v=g[u][i];
                deep[v]=deep[u]+1,f[v][0]=u;
                for(int j=1;j<18 && f[f[v][j-1]][j-1];j++)
                    f[v][j]=f[f[v][j-1]][j-1];
                b.push(v);
            }
    }
}
int LCA(int a,int b){
    int ta=a,tb=b;
    if(deep[a]<deep[b])
        swap(a,b);
    for(int i=17;i>=0;i--)
        if(deep[f[a][i]]>=deep[b])
			a=f[a][i];
	//cout<<"1 "<<a<<' '<<b<<endl;
    if(a==b)
    	return deep[ta]+deep[tb]-deep[a]*2;
    for(int i=17;i>=0;i--){
        if(f[a][i]==f[b][i])
            continue;
        a=f[a][i],b=f[b][i];
    }
    //cout<<"2 "<<f[a][0]<<endl;
    return deep[ta]+deep[tb]-deep[f[a][0]]*2;
}
int main(){
    cin>>n;
    for(int i=1;i<n;i++){
        int u,v;
        cin>>u>>v;
        g[u].push_back(v);
        g[v].push_back(u);
    }
    set_thing();
	int ans=0,p=1;
    cin>>m;
    for(int i=1;i<=m;i++){
        int d;
        cin>>d;
        if(d!=p)
            ans+=LCA(p,d),p=d;
    }
    cout<<ans;
    return 0;
}
